proof_block:
// Per-conjunct trigger priming.
//
// Drop the outer `if (LHS) { ... }` wrap from attempt_01 — the wrap
// surfaced facts as local hypotheses but never propagated to the
// function-end obligation `LHS ==> det_eq`, so the postcondition was
// left unhinted. Instead, emit each ensures conjunct as a flat
// `assert(<conjunct>)`. Verus discharges each one against the ensures
// in place, and the SMT solver now sees the per-run conjuncts on
// identical syntactic shapes for r1 and r2 *at function end*, which is
// where the implication is checked.

let ghost ne1 = r1.1@;
let ghost ne2 = r2.1@;

// ---- ensures conjuncts for r1 ----
assert(post1_netc.my_end_point() == pre_netc.my_end_point());
assert(post1_netc.ok() == !(r1.0 is Fail));
assert(!(r1.0 is Fail)
    ==> post1_netc.ok() && post1_netc.history() == pre_netc.history() + seq![ne1]);
assert(r1.0 is Timeout ==> ne1 is TimeoutReceive);
assert(r1.0 is Packet ==> ne1 is Receive);
assert(r1.0 is Packet ==> r1.0.arrow_Packet_cpacket().abstractable());
assert(r1.0 is Packet ==> r1.0.arrow_Packet_cpacket().dst@ == local_addr@);
assert(r1.0 is Packet
        && !(r1.0.arrow_Packet_cpacket()@.msg is InvalidMessage)
    ==> r1.0.arrow_Packet_cpacket()@
            == abstractify_net_packet_to_sht_packet(ne1.arrow_Receive_r()));
assert(r1.0 is Packet
        && !(r1.0.arrow_Packet_cpacket()@.msg is InvalidMessage)
    ==> r1.0.arrow_Packet_cpacket().msg@
            == sht_demarshal_data(ne1.arrow_Receive_r().msg)@);

// ---- ensures conjuncts for r2 ----
assert(post2_netc.my_end_point() == pre_netc.my_end_point());
assert(post2_netc.ok() == !(r2.0 is Fail));
assert(!(r2.0 is Fail)
    ==> post2_netc.ok() && post2_netc.history() == pre_netc.history() + seq![ne2]);
assert(r2.0 is Timeout ==> ne2 is TimeoutReceive);
assert(r2.0 is Packet ==> ne2 is Receive);
assert(r2.0 is Packet ==> r2.0.arrow_Packet_cpacket().abstractable());
assert(r2.0 is Packet ==> r2.0.arrow_Packet_cpacket().dst@ == local_addr@);
assert(r2.0 is Packet
        && !(r2.0.arrow_Packet_cpacket()@.msg is InvalidMessage)
    ==> r2.0.arrow_Packet_cpacket()@
            == abstractify_net_packet_to_sht_packet(ne2.arrow_Receive_r()));
assert(r2.0 is Packet
        && !(r2.0.arrow_Packet_cpacket()@.msg is InvalidMessage)
    ==> r2.0.arrow_Packet_cpacket().msg@
            == sht_demarshal_data(ne2.arrow_Receive_r().msg)@);

// ---- cross-run alignments forced by the spec ----
// my_end_point is preserved across both runs through pre_netc.
assert(post1_netc.my_end_point() == post2_netc.my_end_point());

// In the Timeout/Timeout sub-case both NetEvents collapse to the unit
// variant, so views and the appended histories all coincide.
if r1.0 is Timeout && r2.0 is Timeout {
    assert(ne1 is TimeoutReceive);
    assert(ne2 is TimeoutReceive);
    lemma_timeout_receive_unique(ne1, ne2);
    assert(ne1 == ne2);
    assert(ne1.view() == ne2.view());
    assert(post1_netc.history() == pre_netc.history() + seq![ne1]);
    assert(post2_netc.history() == pre_netc.history() + seq![ne2]);
    assert(post1_netc.history() == post2_netc.history());
}

// In the Packet/Packet sub-case the dst views collapse through local_addr@.
if r1.0 is Packet && r2.0 is Packet {
    assert(r1.0.arrow_Packet_cpacket().dst@ == r2.0.arrow_Packet_cpacket().dst@);
}

// In the Fail/Fail sub-case the ok-bits align.
if r1.0 is Fail && r2.0 is Fail {
    assert(!post1_netc.ok());
    assert(!post2_netc.ok());
}

helper_lemmas:
// Functional-uniqueness for the unit-variant LIoOp::TimeoutReceive.
// Two values of this variant share no payload, so they are syntactically
// equal as enums and as views.
proof fn lemma_timeout_receive_unique(x: NetEvent, y: NetEvent)
    requires
        x is TimeoutReceive,
        y is TimeoutReceive,
    ensures
        x == y,
        x.view() == y.view(),
{
    assert(x == LIoOp::<AbstractEndPoint, Seq<u8>>::TimeoutReceive{});
    assert(y == LIoOp::<AbstractEndPoint, Seq<u8>>::TimeoutReceive{});
    assert(x.view() == LIoOpView::<AbstractEndPoint, Seq<u8>>::TimeoutReceive{});
    assert(y.view() == LIoOpView::<AbstractEndPoint, Seq<u8>>::TimeoutReceive{});
}

// Functional-uniqueness for the cpacket views of two Packet results that
// share a NetEvent. When both runs' packets are non-Invalid, the ensures
// pins cpacket@ to abstractify_net_packet_to_sht_packet(net_event.arrow_Receive_r()),
// which is a pure spec function — hence agreement on equal NetEvents.
proof fn lemma_packet_cpacket_pinned(
    rr1: ReceiveResult, ne1: NetEvent,
    rr2: ReceiveResult, ne2: NetEvent,
)
    requires
        rr1 is Packet,
        rr2 is Packet,
        ne1 == ne2,
        !(rr1.arrow_Packet_cpacket()@.msg is InvalidMessage),
        !(rr2.arrow_Packet_cpacket()@.msg is InvalidMessage),
        rr1.arrow_Packet_cpacket()@ == abstractify_net_packet_to_sht_packet(ne1.arrow_Receive_r()),
        rr2.arrow_Packet_cpacket()@ == abstractify_net_packet_to_sht_packet(ne2.arrow_Receive_r()),
    ensures
        rr1.arrow_Packet_cpacket()@ == rr2.arrow_Packet_cpacket()@,
{
    assert(ne1.arrow_Receive_r() == ne2.arrow_Receive_r());
    assert(abstractify_net_packet_to_sht_packet(ne1.arrow_Receive_r())
        == abstractify_net_packet_to_sht_packet(ne2.arrow_Receive_r()));
}
